+    // Refresh helpers
+    scheduleAutoRefresh() {
+      if (this.autoRefreshHandle) {
+        clearInterval(this.autoRefreshHandle);
+        this.autoRefreshHandle = null;
+      }
+      if (!this.autoRefreshEnabled) {
+        return;
+      }
+      this.autoRefreshHandle = setInterval(() => {
+        this.fetchLatestMessages({ silent: true });
+      }, this.autoRefreshSeconds * 1000);
+    },
+
+    handleAutoRefreshToggle() {
+      if (this.autoRefreshEnabled) {
+        this.scheduleAutoRefresh();
+      } else if (this.autoRefreshHandle) {
+        clearInterval(this.autoRefreshHandle);
+        this.autoRefreshHandle = null;
+      }
+    },
+
+    async fetchLatestMessages(options = {}) {
+      const { silent = false } = options;
+      if (this.isRefreshing) {
+        return;
+      }
+      this.isRefreshing = true;
+      this.refreshError = null;
+
+      const previouslySelectedId = this.selectedMessage?.id ?? null;
+      const previouslySelectedSet = new Set(this.selectedMessages || []);
+
+      try {
+        const response = await fetch(`/mail/api/unified-inbox?limit=500&include_projects=false`, {
+          headers: { Accept: 'application/json' },
+          cache: 'no-store'
+        });
+        if (!response.ok) {
+          throw new Error(`HTTP ${response.status}`);
+        }
+        const payload = await response.json();
+        const incomingMessages = Array.isArray(payload.messages) ? payload.messages : [];
+
+        this.allMessages = incomingMessages;
+        this.filterMessages();
+
+        if (previouslySelectedId) {
+          const nextSelection = this.filteredMessages.find((m) => m.id === previouslySelectedId);
+          if (nextSelection) {
+            this.selectMessage(nextSelection);
+          } else {
+            this.selectedMessage = null;
+          }
+        } else if (this.viewMode === 'split' && !this.selectedMessage && this.filteredMessages.length > 0) {
+          this.selectMessage(this.filteredMessages[0]);
+        }
+
+        if (previouslySelectedSet.size > 0) {
+          this.selectedMessages = this.filteredMessages
+            .filter((m) => previouslySelectedSet.has(m.id))
+            .map((m) => m.id);
+        } else if (this.selectedMessages.length > 0) {
+          this.selectedMessages = [];
+        }
+
+        this.lastRefreshTime = new Date();
+
+        if (!silent && typeof window.showToast === 'function') {
+          window.showToast('Inbox refreshed', 'success');
+        }
+      } catch (error) {
+        console.error('Unified inbox refresh failed:', error);
+        this.refreshError = 'Refresh failed. Retrying soon.';
+        if (!silent && typeof window.showToast === 'function') {
+          window.showToast('Failed to refresh inbox', 'error');
+        }
+      } finally {
+        this.isRefreshing = false;
+        if (!silent) {
+          this.scheduleAutoRefresh();
+        }
+      }
+    },
